In packaging/installer/am4opscenter.iss, add to the [Code] section:

  procedure CurUninstallStepChanged(CurUninstallStep: TUninstallStep);
  var
    UserDataDir: String;
    Response: Integer;
  begin
    if CurUninstallStep = usPostUninstall then
    begin
      UserDataDir := ExpandConstant('{userappdata}\AM4OpsCenter');
      if DirExists(UserDataDir) then
      begin
        Response := MsgBox(
          'Do you also want to delete your AM4 Ops Center data (database, credentials, logs)?' + #13#10 + #13#10 +
          'Location: ' + UserDataDir + #13#10 + #13#10 +
          'Click No to keep your data for future reinstalls.',
          mbConfirmation, MB_YESNO or MB_DEFBUTTON2);
        if Response = IDYES then
          DelTree(UserDataDir, True, True, True);
      end;
    end;
  end;

Also: before uninstall begins, check if AM4OpsCenter.exe is running (via FindWindow or tasklist) and if so, prompt the user to close it or auto-run AM4OpsCenter-Stop.exe.

Document this behavior in packaging/README.md under 'Uninstall'.
